use std::sync::{Arc, Mutex};
use std::thread;
use std::collections::HashMap;

#[derive(Clone)]
pub struct Inventory {
    items: Arc<Mutex<HashMap<String, u32>>>,
}

impl Inventory {
    pub fn new() -> Self {
        Inventory {
            items: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    pub fn add_item(&self, item_id: String, quantity: u32) {
        let mut items = self.items.lock().unwrap();
        *items.entry(item_id).or_insert(0) += quantity;
    }

    pub fn check_stock(&self, item_id: &str) -> Option<u32> {
        let items = self.items.lock().unwrap();
        items.get(item_id).copied()
    }

    pub fn try_decrement(&self, item_id: &str, quantity: u32) -> Result<u32, String> {
        let mut items = self.items.lock().unwrap();
        
        let current_stock = items.get(item_id).copied().ok_or_else(|| {
            format!("Item '{}' not found in inventory", item_id)
        })?;

        if current_stock < quantity {
            return Err(format!(
                "Insufficient stock for '{}': requested {}, available {}",
                item_id, quantity, current_stock
            ));
        }

        items.insert(item_id.to_string(), current_stock - quantity);
        Ok(current_stock - quantity)
    }

    pub fn decrement_multiple(&self, items_to_decrement: Vec<(String, u32)>) -> Result<(), String> {
        let mut items = self.items.lock().unwrap();
        
        for (item_id, quantity) in &items_to_decrement {
            let current_stock = items.get(item_id).copied().ok_or_else(|| {
                format!("Item '{}' not found in inventory", item_id)
            })?;

            if current_stock < *quantity {
                return Err(format!(
                    "Insufficient stock for '{}': requested {}, available {}",
                    item_id, quantity, current_stock
                ));
            }
        }

        for (item_id, quantity) in items_to_decrement {
            let current_stock = items.get(&item_id).unwrap();
            items.insert(item_id, current_stock - quantity);
        }

        Ok(())
    }
}

pub fn run_concurrent_inventory_test() {
    let inventory = Inventory::new();
    
    inventory.add_item("laptop".to_string(), 100);
    inventory.add_item("mouse".to_string(), 500);
    inventory.add_item("keyboard".to_string(), 300);

    let mut handles = vec![];

    for i in 0..10 {
        let inv = inventory.clone();
        let handle = thread::spawn(move || {
            for j in 0..10 {
                match inv.try_decrement("laptop", 1) {
                    Ok(remaining) => {
                        println!("Thread {} iteration {}: Decremented laptop, remaining: {}", i, j, remaining);
                    }
                    Err(e) => {
                        println!("Thread {} iteration {}: Failed to decrement: {}", i, j, e);
                    }
                }
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("Final laptop stock: {:?}", inventory.check_stock("laptop"));
    println!("Final mouse stock: {:?}", inventory.check_stock("mouse"));
    println!("Final keyboard stock: {:?}", inventory.check_stock("keyboard"));
}